package auth

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"sync"
	"time"
)

// TokenInfo stores information about a bearer token.
type TokenInfo struct {
	Username  string
	ExpiresAt time.Time
}

// AuthManager manages authentication tokens.
type AuthManager struct {
	mu     sync.RWMutex
	tokens map[string]TokenInfo
}

// NewAuthManager creates a new AuthManager.
func NewAuthManager() *AuthManager {
	return &AuthManager{
		tokens: make(map[string]TokenInfo),
	}
}

// Login creates a new token for the given username.
func (am *AuthManager) Login(username string) (string, error) {
	if username == "" {
		return "", fmt.Errorf("empty username")
	}

	token := generateToken()
	am.mu.Lock()
	am.tokens[token] = TokenInfo{
		Username:  username,
		ExpiresAt: time.Now().Add(1 * time.Hour),
	}
	am.mu.Unlock()
	return token, nil
}

// Logout invalidates a token.
func (am *AuthManager) Logout(token string) error {
	am.mu.Lock()
	defer am.mu.Unlock()

	if _, ok := am.tokens[token]; !ok {
		return fmt.Errorf("invalid token")
	}
	delete(am.tokens, token)
	return nil
}

// Validate checks if a token is valid and not expired.
func (am *AuthManager) Validate(token string) (string, error) {
	am.mu.RLock()
	defer am.mu.RUnlock()

	info, ok := am.tokens[token]
	if !ok {
		return "", fmt.Errorf("invalid token")
	}
	if time.Now().After(info.ExpiresAt) {
		return "", fmt.Errorf("token expired")
	}
	return info.Username, nil
}

// LoadTokens loads pre-configured tokens (from the -t file).
func (am *AuthManager) LoadTokens(tokenMap map[string]string) {
	am.mu.Lock()
	defer am.mu.Unlock()

	for username, token := range tokenMap {
		am.tokens[token] = TokenInfo{
			Username:  username,
			ExpiresAt: time.Now().Add(24 * time.Hour),
		}
	}
}

func generateToken() string {
	b := make([]byte, 16)
	_, _ = rand.Read(b)
	return base64.RawURLEncoding.EncodeToString(b)
}

package db

import (
	"context"
	"sync"

	"github.com/RICE-COMP318-FALL24/owldb-bench/skiplist"
)

// Collection represents a collection of documents indexed by a skip list.
type Collection struct {
	docs *skiplist.SkipList[string, *Document]
}

// NewCollection creates a new empty collection.
func NewCollection() *Collection {
	return &Collection{
		docs: skiplist.New[string, *Document](),
	}
}

// Upsert inserts or updates a document in the collection.
func (c *Collection) Upsert(key string, check skiplist.UpdateCheck[string, *Document]) (bool, error) {
	return c.docs.Upsert(key, check)
}

// Find retrieves a document by name.
func (c *Collection) Find(key string) (*Document, bool) {
	return c.docs.Find(key)
}

// Remove removes a document by name.
func (c *Collection) Remove(key string) (*Document, bool) {
	return c.docs.Remove(key)
}

// Query returns documents with keys in [start, end].
func (c *Collection) Query(ctx context.Context, start, end string) ([]skiplist.Pair[string, *Document], error) {
	return c.docs.Query(ctx, start, end)
}

// QueryAll returns all documents in order.
func (c *Collection) QueryAll(ctx context.Context) ([]skiplist.Pair[string, *Document], error) {
	return c.docs.QueryAll(ctx)
}

// CollectionMap holds named collections using a skip list.
type CollectionMap struct {
	cols *skiplist.SkipList[string, *Collection]
	mu   sync.RWMutex
}

// NewCollectionMap creates a new CollectionMap.
func NewCollectionMap() *CollectionMap {
	return &CollectionMap{
		cols: skiplist.New[string, *Collection](),
	}
}

// Create creates a new collection with the given name. Returns false if it already exists.
func (cm *CollectionMap) Create(name string) (*Collection, bool, error) {
	var created *Collection
	var wasCreated bool
	_, err := cm.cols.Upsert(name, func(key string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			created = curr
			wasCreated = false
			return curr, nil
		}
		c := NewCollection()
		created = c
		wasCreated = true
		return c, nil
	})
	if err != nil {
		return nil, false, err
	}
	return created, wasCreated, nil
}

// Find looks up a collection by name.
func (cm *CollectionMap) Find(name string) (*Collection, bool) {
	return cm.cols.Find(name)
}

// Remove removes a collection by name.
func (cm *CollectionMap) Remove(name string) (*Collection, bool) {
	return cm.cols.Remove(name)
}

package db

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"sync"

	"github.com/RICE-COMP318-FALL24/owldb-bench/jsondata"
	"github.com/RICE-COMP318-FALL24/owldb-bench/skiplist"
	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

// DatabaseServer holds all databases and the document schema validator.
type DatabaseServer struct {
	databases *skiplist.SkipList[string, *Collection]
	schema    *jsonschema.Schema
	mu        sync.RWMutex
	subs      *SubscriptionManager
}

// NewDatabaseServer creates a new DatabaseServer with the given schema.
func NewDatabaseServer(schema *jsonschema.Schema) *DatabaseServer {
	return &DatabaseServer{
		databases: skiplist.New[string, *Collection](),
		schema:    schema,
		subs:      NewSubscriptionManager(),
	}
}

// Subs returns the subscription manager.
func (ds *DatabaseServer) Subs() *SubscriptionManager {
	return ds.subs
}

// CreateDatabase creates a new database. Returns error if it already exists.
func (ds *DatabaseServer) CreateDatabase(name string) error {
	var alreadyExists bool
	_, err := ds.databases.Upsert(name, func(key string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			alreadyExists = true
			return curr, fmt.Errorf("database already exists")
		}
		return NewCollection(), nil
	})
	if alreadyExists {
		return fmt.Errorf("database already exists")
	}
	return err
}

// DeleteDatabase removes a database.
func (ds *DatabaseServer) DeleteDatabase(name string) error {
	_, removed := ds.databases.Remove(name)
	if !removed {
		return fmt.Errorf("database does not exist")
	}
	// Notify subscribers about the deletion
	ds.subs.NotifyDelete("/v1/" + name + "/")
	return nil
}

// GetDatabase returns the top-level collection for a database.
func (ds *DatabaseServer) GetDatabase(name string) (*Collection, bool) {
	return ds.databases.Find(name)
}

// parsePath splits a path like "dbname/doc1/col1/doc2" into components.
// Returns the database name and remaining path segments.
func parsePath(path string) (string, []string) {
	parts := strings.Split(path, "/")
	if len(parts) == 0 {
		return "", nil
	}
	return parts[0], parts[1:]
}

// resolveCollection resolves the collection path, starting from a database.
// path components alternate: doc, col, doc, col, ...
// If isCollection is true, the last component is a collection name.
// Returns the final collection and the document/collection name.
func (ds *DatabaseServer) resolveDocPath(path string) (collection *Collection, docName string, fullPath string, err error) {
	dbName, rest := parsePath(path)
	if dbName == "" {
		return nil, "", "", fmt.Errorf("empty path")
	}

	db, ok := ds.databases.Find(dbName)
	if !ok {
		return nil, "", "", fmt.Errorf("database does not exist")
	}

	if len(rest) == 0 {
		return nil, "", "", fmt.Errorf("no document specified")
	}

	// Navigate: rest[0]=doc, rest[1]=col, rest[2]=doc, ...
	currentCol := db
	for i := 0; i < len(rest)-1; i++ {
		name := rest[i]
		if i%2 == 0 {
			// Document name - find the document
			doc, found := currentCol.Find(name)
			if !found {
				if i%2 == 0 && i == len(rest)-2 {
					// Parent doc doesn't exist
					return nil, "", "", fmt.Errorf("document does not exist")
				}
				return nil, "", "", fmt.Errorf("document does not exist")
			}
			if i+1 < len(rest)-1 {
				// Next is a collection name
				colName := rest[i+1]
				col, found := doc.Collections.Find(colName)
				if !found {
					return nil, "", "", fmt.Errorf("collection does not exist")
				}
				currentCol = col
				i++ // Skip the collection name
			}
		}
	}

	docName = rest[len(rest)-1]
	fullPath = "/v1/" + path
	return currentCol, docName, fullPath, nil
}

// resolveCollectionPath resolves a path ending with a collection.
// Path: dbname/doc/col/doc/col - the trailing slash has been removed.
func (ds *DatabaseServer) resolveCollectionPath(path string) (collection *Collection, colPath string, err error) {
	dbName, rest := parsePath(path)
	if dbName == "" {
		return nil, "", fmt.Errorf("empty path")
	}

	db, ok := ds.databases.Find(dbName)
	if !ok {
		return nil, "", fmt.Errorf("database does not exist")
	}

	if len(rest) == 0 {
		// Just the database (top-level collection)
		return db, "/v1/" + dbName + "/", nil
	}

	// Navigate doc/col/doc/col pattern
	currentCol := db
	for i := 0; i < len(rest); i += 2 {
		docName := rest[i]
		doc, found := currentCol.Find(docName)
		if !found {
			return nil, "", fmt.Errorf("document does not exist")
		}
		if i+1 < len(rest) {
			colName := rest[i+1]
			col, found := doc.Collections.Find(colName)
			if !found {
				return nil, "", fmt.Errorf("collection does not exist")
			}
			currentCol = col
		} else {
			return nil, "", fmt.Errorf("path does not end with collection")
		}
	}

	return currentCol, "/v1/" + path + "/", nil
}

// resolveParentForCollection resolves the parent document for creating a new collection.
// path = dbname/doc/col/doc/newcol - we need to find the parent document
func (ds *DatabaseServer) resolveParentForCollection(path string) (doc *Document, colName string, fullPath string, err error) {
	dbName, rest := parsePath(path)
	if dbName == "" {
		return nil, "", "", fmt.Errorf("empty path")
	}

	_, ok := ds.databases.Find(dbName)
	if !ok {
		return nil, "", "", fmt.Errorf("database does not exist")
	}

	if len(rest) < 2 {
		return nil, "", "", fmt.Errorf("invalid collection path")
	}

	// The last element is the collection name, everything before is a doc path
	colName = rest[len(rest)-1]
	docPath := strings.Join(append([]string{dbName}, rest[:len(rest)-1]...), "/")

	col, docName, _, err := ds.resolveDocPath(docPath)
	if err != nil {
		return nil, "", "", err
	}

	foundDoc, found := col.Find(docName)
	if !found {
		return nil, "", "", fmt.Errorf("document does not exist")
	}

	fullPath = "/v1/" + path + "/"
	return foundDoc, colName, fullPath, nil
}

// ValidateDocument validates a JSON document against the schema.
func (ds *DatabaseServer) ValidateDocument(data []byte) error {
	if ds.schema == nil {
		return nil
	}

	var v jsondata.JSONValue
	if err := json.Unmarshal(data, &v); err != nil {
		return fmt.Errorf("invalid JSON: %w", err)
	}

	// Validate using the schema
	var raw interface{}
	if err := json.Unmarshal(data, &raw); err != nil {
		return fmt.Errorf("invalid JSON: %w", err)
	}

	if err := ds.schema.Validate(raw); err != nil {
		return fmt.Errorf("document does not match schema: %w", err)
	}
	return nil
}

// PutDocument creates or updates a document.
func (ds *DatabaseServer) PutDocument(path string, data []byte, username string, noOverwrite bool) (created bool, uri string, err error) {
	if err := ds.ValidateDocument(data); err != nil {
		return false, "", err
	}

	col, docName, fullPath, err := ds.resolveDocPath(path)
	if err != nil {
		return false, "", err
	}

	var wasCreated bool
	_, upsertErr := col.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if exists {
			if noOverwrite {
				return curr, fmt.Errorf("document already exists")
			}
			// Overwrite: preserve collections
			curr.Update(data, username)
			wasCreated = false
			return curr, nil
		}
		wasCreated = true
		return NewDocument(data, username), nil
	})
	if upsertErr != nil {
		return false, fullPath, upsertErr
	}

	// Notify subscribers
	doc, found := col.Find(docName)
	if found {
		ds.subs.NotifyUpdate(fullPath, data, doc.Meta)
	}

	return wasCreated, fullPath, nil
}

// PostDocument creates a new document with a server-generated name.
func (ds *DatabaseServer) PostDocument(colPath string, data []byte, username string) (uri string, err error) {
	if err := ds.ValidateDocument(data); err != nil {
		return "", err
	}

	// Resolve the collection
	var col *Collection
	dbName, rest := parsePath(colPath)
	if dbName == "" {
		return "", fmt.Errorf("empty path")
	}

	db, ok := ds.databases.Find(dbName)
	if !ok {
		return "", fmt.Errorf("database does not exist")
	}

	if len(rest) == 0 {
		col = db
	} else {
		var colErr error
		col, _, colErr = ds.resolveCollectionPath(colPath)
		if colErr != nil {
			return "", fmt.Errorf("collection does not exist")
		}
	}

	// Generate unique name
	docName := generateID()

	doc := NewDocument(data, username)
	_, err = col.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		return doc, nil
	})
	if err != nil {
		return "", err
	}

	fullPath := "/v1/" + colPath + docName
	if !strings.HasSuffix(colPath, "/") {
		fullPath = "/v1/" + colPath + "/" + docName
	}

	// Notify subscribers
	ds.subs.NotifyUpdate(fullPath, data, doc.Meta)

	return fullPath, nil
}

// GetDocument retrieves a document by path.
func (ds *DatabaseServer) GetDocument(path string) (data []byte, meta Metadata, fullPath string, err error) {
	col, docName, fullPath, err := ds.resolveDocPath(path)
	if err != nil {
		return nil, Metadata{}, "", err
	}

	doc, found := col.Find(docName)
	if !found {
		return nil, Metadata{}, fullPath, fmt.Errorf("document does not exist")
	}

	return doc.Data, doc.Meta, fullPath, nil
}

// DeleteDocument removes a document.
func (ds *DatabaseServer) DeleteDocument(path string) error {
	col, docName, fullPath, err := ds.resolveDocPath(path)
	if err != nil {
		return err
	}

	_, removed := col.Remove(docName)
	if !removed {
		return fmt.Errorf("document does not exist")
	}

	// Notify subscribers
	ds.subs.NotifyDelete(fullPath)
	return nil
}

// GetCollectionDocs retrieves all documents in a collection with optional interval.
func (ds *DatabaseServer) GetCollectionDocs(path string, start, end string, hasStart, hasEnd bool) ([]DocResponse, error) {
	var col *Collection
	dbName, rest := parsePath(path)
	if dbName == "" {
		return nil, fmt.Errorf("empty path")
	}

	db, ok := ds.databases.Find(dbName)
	if !ok {
		return nil, fmt.Errorf("database does not exist")
	}

	var colPath string
	if len(rest) == 0 {
		col = db
		colPath = "/v1/" + dbName + "/"
	} else {
		var err error
		col, colPath, err = ds.resolveCollectionPath(path)
		if err != nil {
			return nil, err
		}
	}

	ctx := context.Background()
	var pairs []skiplist.Pair[string, *Document]
	var err error

	if !hasStart && !hasEnd {
		pairs, err = col.QueryAll(ctx)
	} else if hasStart && hasEnd {
		pairs, err = col.Query(ctx, start, end)
	} else if hasStart {
		// Only low bound - use start to max
		pairs, err = col.QueryAll(ctx)
		if err == nil {
			filtered := make([]skiplist.Pair[string, *Document], 0)
			for _, p := range pairs {
				if p.Key >= start {
					filtered = append(filtered, p)
				}
			}
			pairs = filtered
		}
	} else {
		// Only high bound
		pairs, err = col.QueryAll(ctx)
		if err == nil {
			filtered := make([]skiplist.Pair[string, *Document], 0)
			for _, p := range pairs {
				if p.Key <= end {
					filtered = append(filtered, p)
				}
			}
			pairs = filtered
		}
	}

	if err != nil {
		return nil, err
	}

	var results []DocResponse
	_ = colPath
	for _, p := range pairs {
		docFullPath := strings.TrimSuffix(colPath, "/") + "/" + p.Key
		results = append(results, DocResponse{
			Path: docFullPath,
			Doc:  json.RawMessage(p.Value.Data),
			Meta: p.Value.Meta,
		})
	}
	return results, nil
}

// CreateCollection creates a new sub-collection.
func (ds *DatabaseServer) CreateCollection(path string) (string, error) {
	// Path is like dbname/doc/colname
	doc, colName, fullPath, err := ds.resolveParentForCollection(path)
	if err != nil {
		return "", err
	}

	_, created, err := doc.Collections.Create(colName)
	if err != nil {
		return "", err
	}
	if !created {
		return "", fmt.Errorf("collection already exists")
	}
	return fullPath, nil
}

// DeleteCollection removes a sub-collection.
func (ds *DatabaseServer) DeleteCollection(path string) error {
	// Path: dbname/doc/.../colname
	dbName, rest := parsePath(path)
	if dbName == "" {
		return fmt.Errorf("empty path")
	}

	_, ok := ds.databases.Find(dbName)
	if !ok {
		return fmt.Errorf("database does not exist")
	}

	if len(rest) < 2 {
		return fmt.Errorf("invalid collection path")
	}

	colName := rest[len(rest)-1]
	docPath := strings.Join(append([]string{dbName}, rest[:len(rest)-1]...), "/")

	col, docName, _, err := ds.resolveDocPath(docPath)
	if err != nil {
		return err
	}

	doc, found := col.Find(docName)
	if !found {
		return fmt.Errorf("document does not exist")
	}

	_, removed := doc.Collections.Remove(colName)
	if !removed {
		return fmt.Errorf("collection does not exist")
	}

	// Notify subscribers
	ds.subs.NotifyDelete("/v1/" + path + "/")
	return nil
}

// PatchDocument applies patches to a document atomically.
func (ds *DatabaseServer) PatchDocument(path string, patches []PatchOp, username string) (uri string, patchFailed bool, message string, err error) {
	col, docName, fullPath, err := ds.resolveDocPath(path)
	if err != nil {
		return "", false, "", err
	}

	var resultFailed bool
	var resultMsg string

	_, upsertErr := col.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if !exists {
			return curr, fmt.Errorf("document does not exist")
		}

		// Parse current document
		var docValue jsondata.JSONValue
		if err := json.Unmarshal(curr.Data, &docValue); err != nil {
			resultFailed = true
			resultMsg = "failed to parse document: " + err.Error()
			return curr, nil
		}

		// Apply patches
		newValue, patchErr := applyPatches(docValue, patches)
		if patchErr != nil {
			resultFailed = true
			resultMsg = patchErr.Error()
			return curr, nil
		}

		// Marshal back
		newData, err := json.Marshal(newValue)
		if err != nil {
			resultFailed = true
			resultMsg = "failed to marshal patched document"
			return curr, nil
		}

		// Validate
		if valErr := ds.ValidateDocument(newData); valErr != nil {
			resultFailed = true
			resultMsg = "patched document does not match schema: " + valErr.Error()
			return curr, nil
		}

		curr.Update(newData, username)
		resultFailed = false
		resultMsg = "patch applied"
		return curr, nil
	})

	if upsertErr != nil {
		if upsertErr.Error() == "document does not exist" {
			return fullPath, false, "", fmt.Errorf("document does not exist")
		}
		return fullPath, true, upsertErr.Error(), nil
	}

	// Notify subscribers if patch succeeded
	if !resultFailed {
		doc, found := col.Find(docName)
		if found {
			ds.subs.NotifyUpdate(fullPath, doc.Data, doc.Meta)
		}
	}

	return fullPath, resultFailed, resultMsg, nil
}

// DocResponse is used for JSON responses.
type DocResponse struct {
	Path string          `json:"path"`
	Doc  json.RawMessage `json:"doc"`
	Meta Metadata        `json:"meta"`
}

package db

import (
	"time"
)

// Metadata holds document metadata.
type Metadata struct {
	CreatedBy      string `json:"createdBy"`
	CreatedAt      int64  `json:"createdAt"`
	LastModifiedBy string `json:"lastModifiedBy"`
	LastModifiedAt int64  `json:"lastModifiedAt"`
}

// Document represents a stored document with its raw JSON, metadata, and child collections.
type Document struct {
	Data        []byte
	Meta        Metadata
	Collections *CollectionMap
}

// NewDocument creates a new document.
func NewDocument(data []byte, username string) *Document {
	now := time.Now().UnixMilli()
	return &Document{
		Data: data,
		Meta: Metadata{
			CreatedBy:      username,
			CreatedAt:      now,
			LastModifiedBy: username,
			LastModifiedAt: now,
		},
		Collections: NewCollectionMap(),
	}
}

// Update replaces document data and updates modification metadata.
func (d *Document) Update(data []byte, username string) {
	d.Data = data
	d.Meta.LastModifiedBy = username
	d.Meta.LastModifiedAt = time.Now().UnixMilli()
}

package db

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/RICE-COMP318-FALL24/owldb-bench/jsondata"
)

// PatchOp represents a single patch operation.
type PatchOp struct {
	Op    string          `json:"op"`
	Path  string          `json:"path"`
	Value json.RawMessage `json:"value"`
}

// applyPatches applies a list of patch operations to a JSONValue.
func applyPatches(doc jsondata.JSONValue, patches []PatchOp) (jsondata.JSONValue, error) {
	current := doc
	for _, patch := range patches {
		switch patch.Op {
		case "ArrayAdd":
			result, err := applyArrayAdd(current, patch.Path, patch.Value)
			if err != nil {
				return doc, err
			}
			current = result
		case "ArrayRemove":
			result, err := applyArrayRemove(current, patch.Path, patch.Value)
			if err != nil {
				return doc, err
			}
			current = result
		case "ObjectAdd":
			result, err := applyObjectAdd(current, patch.Path, patch.Value)
			if err != nil {
				return doc, err
			}
			current = result
		default:
			return doc, fmt.Errorf("unknown patch operation: %s", patch.Op)
		}
	}
	return current, nil
}

// parseJSONPointer parses a JSON pointer like "/a/b/c" into ["a", "b", "c"].
func parseJSONPointer(pointer string) ([]string, error) {
	if pointer == "" {
		return nil, nil
	}
	if !strings.HasPrefix(pointer, "/") {
		return nil, fmt.Errorf("invalid JSON pointer: %s", pointer)
	}
	parts := strings.Split(pointer[1:], "/")
	// Unescape ~1 and ~0
	for i, p := range parts {
		p = strings.ReplaceAll(p, "~1", "/")
		p = strings.ReplaceAll(p, "~0", "~")
		parts[i] = p
	}
	return parts, nil
}

// navigateToParent navigates the JSON structure to the parent of the target.
// Returns the raw interface{} at the parent level.
func navigateJSON(data interface{}, path []string) (interface{}, error) {
	current := data
	for _, key := range path {
		switch v := current.(type) {
		case map[string]interface{}:
			child, ok := v[key]
			if !ok {
				return nil, fmt.Errorf("path element '%s' not found", key)
			}
			current = child
		default:
			return nil, fmt.Errorf("cannot navigate into non-object type at '%s'", key)
		}
	}
	return current, nil
}

func applyArrayAdd(doc jsondata.JSONValue, pointer string, valueRaw json.RawMessage) (jsondata.JSONValue, error) {
	pathParts, err := parseJSONPointer(pointer)
	if err != nil {
		return doc, err
	}

	// Convert doc to raw interface for manipulation
	docBytes, err := json.Marshal(doc)
	if err != nil {
		return doc, err
	}
	var raw interface{}
	if err := json.Unmarshal(docBytes, &raw); err != nil {
		return doc, err
	}

	// Unmarshal the value to add
	var patchValue interface{}
	if err := json.Unmarshal(valueRaw, &patchValue); err != nil {
		return doc, err
	}

	// Navigate to the target array
	target, err := navigateJSON(raw, pathParts)
	if err != nil {
		return doc, err
	}

	arr, ok := target.([]interface{})
	if !ok {
		return doc, fmt.Errorf("target is not an array")
	}

	// Check if value already exists
	for _, item := range arr {
		if jsonEqual(item, patchValue) {
			// Already present, no change but not an error
			return doc, nil
		}
	}

	// Add value
	arr = append(arr, patchValue)

	// Set it back
	if err := setJSON(raw, pathParts, arr); err != nil {
		return doc, err
	}

	// Convert back to JSONValue
	newBytes, err := json.Marshal(raw)
	if err != nil {
		return doc, err
	}
	var result jsondata.JSONValue
	if err := json.Unmarshal(newBytes, &result); err != nil {
		return doc, err
	}
	return result, nil
}

func applyArrayRemove(doc jsondata.JSONValue, pointer string, valueRaw json.RawMessage) (jsondata.JSONValue, error) {
	pathParts, err := parseJSONPointer(pointer)
	if err != nil {
		return doc, err
	}

	docBytes, err := json.Marshal(doc)
	if err != nil {
		return doc, err
	}
	var raw interface{}
	if err := json.Unmarshal(docBytes, &raw); err != nil {
		return doc, err
	}

	var patchValue interface{}
	if err := json.Unmarshal(valueRaw, &patchValue); err != nil {
		return doc, err
	}

	target, err := navigateJSON(raw, pathParts)
	if err != nil {
		return doc, err
	}

	arr, ok := target.([]interface{})
	if !ok {
		return doc, fmt.Errorf("target is not an array")
	}

	// Remove matching values
	newArr := make([]interface{}, 0, len(arr))
	for _, item := range arr {
		if !jsonEqual(item, patchValue) {
			newArr = append(newArr, item)
		}
	}

	if err := setJSON(raw, pathParts, newArr); err != nil {
		return doc, err
	}

	newBytes, err := json.Marshal(raw)
	if err != nil {
		return doc, err
	}
	var result jsondata.JSONValue
	if err := json.Unmarshal(newBytes, &result); err != nil {
		return doc, err
	}
	return result, nil
}

func applyObjectAdd(doc jsondata.JSONValue, pointer string, valueRaw json.RawMessage) (jsondata.JSONValue, error) {
	pathParts, err := parseJSONPointer(pointer)
	if err != nil {
		return doc, err
	}
	if len(pathParts) == 0 {
		return doc, fmt.Errorf("empty path for ObjectAdd")
	}

	docBytes, err := json.Marshal(doc)
	if err != nil {
		return doc, err
	}
	var raw interface{}
	if err := json.Unmarshal(docBytes, &raw); err != nil {
		return doc, err
	}

	var patchValue interface{}
	if err := json.Unmarshal(valueRaw, &patchValue); err != nil {
		return doc, err
	}

	// Navigate to the parent object (path without last element)
	parentPath := pathParts[:len(pathParts)-1]
	propName := pathParts[len(pathParts)-1]

	target, err := navigateJSON(raw, parentPath)
	if err != nil {
		return doc, err
	}

	obj, ok := target.(map[string]interface{})
	if !ok {
		return doc, fmt.Errorf("target is not an object")
	}

	// Only add if property doesn't already exist
	if _, exists := obj[propName]; exists {
		// Property exists, don't overwrite - but this is not a failure
		return doc, nil
	}

	obj[propName] = patchValue

	newBytes, err := json.Marshal(raw)
	if err != nil {
		return doc, err
	}
	var result jsondata.JSONValue
	if err := json.Unmarshal(newBytes, &result); err != nil {
		return doc, err
	}
	return result, nil
}

// setJSON sets a value at a given path in a JSON structure.
func setJSON(root interface{}, path []string, value interface{}) error {
	if len(path) == 0 {
		return fmt.Errorf("empty path")
	}

	parent, err := navigateJSON(root, path[:len(path)-1])
	if err != nil {
		return err
	}

	key := path[len(path)-1]
	switch p := parent.(type) {
	case map[string]interface{}:
		p[key] = value
		return nil
	default:
		return fmt.Errorf("cannot set key in non-object type")
	}
}

// jsonEqual compares two JSON values for deep equality.
func jsonEqual(a, b interface{}) bool {
	aBytes, err1 := json.Marshal(a)
	bBytes, err2 := json.Marshal(b)
	if err1 != nil || err2 != nil {
		return false
	}
	return string(aBytes) == string(bBytes)
}

package db

import (
	"encoding/json"
	"fmt"
	"strings"
	"sync"
	"time"
)

// Subscriber represents a single SSE subscriber.
type Subscriber struct {
	ID       string
	Path     string
	Interval *IntervalFilter
	Events   chan SSEEvent
	Done     chan struct{}
}

// IntervalFilter defines an interval for collection subscriptions.
type IntervalFilter struct {
	HasLow  bool
	Low     string
	HasHigh bool
	High    string
}

// Matches returns true if the docName is within the interval.
func (f *IntervalFilter) Matches(docName string) bool {
	if f == nil {
		return true
	}
	if f.HasLow && docName < f.Low {
		return false
	}
	if f.HasHigh && docName > f.High {
		return false
	}
	return true
}

// SSEEvent represents a server-sent event.
type SSEEvent struct {
	EventType string
	Data      string
	ID        string
}

// SubscriptionManager manages all active subscriptions.
type SubscriptionManager struct {
	mu          sync.RWMutex
	subscribers map[string]*Subscriber
	nextID      int
}

// NewSubscriptionManager creates a new SubscriptionManager.
func NewSubscriptionManager() *SubscriptionManager {
	return &SubscriptionManager{
		subscribers: make(map[string]*Subscriber),
	}
}

// Subscribe adds a new subscriber and returns it.
func (sm *SubscriptionManager) Subscribe(path string, interval *IntervalFilter) *Subscriber {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	sm.nextID++
	id := fmt.Sprintf("sub_%d", sm.nextID)

	sub := &Subscriber{
		ID:       id,
		Path:     path,
		Interval: interval,
		Events:   make(chan SSEEvent, 100),
		Done:     make(chan struct{}),
	}
	sm.subscribers[id] = sub
	return sub
}

// Unsubscribe removes a subscriber.
func (sm *SubscriptionManager) Unsubscribe(id string) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	if sub, ok := sm.subscribers[id]; ok {
		close(sub.Done)
		delete(sm.subscribers, id)
	}
}

// NotifyUpdate sends an update event to matching subscribers.
func (sm *SubscriptionManager) NotifyUpdate(docPath string, data []byte, meta Metadata) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()

	eventID := fmt.Sprintf("%d", time.Now().UnixMilli())

	metaJSON, _ := json.Marshal(meta)
	eventData := fmt.Sprintf(`{"path":%s,"doc":%s,"meta":%s}`,
		jsonString(docPath), string(data), string(metaJSON))

	event := SSEEvent{
		EventType: "update",
		Data:      eventData,
		ID:        eventID,
	}

	for _, sub := range sm.subscribers {
		if matchesSubscription(sub, docPath) {
			select {
			case sub.Events <- event:
			default:
				// Buffer full, skip
			}
		}
	}
}

// NotifyDelete sends a delete event to matching subscribers.
func (sm *SubscriptionManager) NotifyDelete(path string) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()

	eventID := fmt.Sprintf("%d", time.Now().UnixMilli())

	event := SSEEvent{
		EventType: "delete",
		Data:      jsonString(path),
		ID:        eventID,
	}

	for _, sub := range sm.subscribers {
		if matchesSubscription(sub, path) {
			select {
			case sub.Events <- event:
			default:
			}
		}
	}
}

// matchesSubscription checks if a document path matches a subscription.
func matchesSubscription(sub *Subscriber, eventPath string) bool {
	subPath := sub.Path

	// Document subscription: exact match
	if !strings.HasSuffix(subPath, "/") {
		return eventPath == subPath
	}

	// Collection subscription: event path should be a direct child
	// subPath = /v1/db/ or /v1/db/doc/col/
	// eventPath = /v1/db/doc1 or /v1/db/doc/col/doc1

	// Check if the event is a delete of the collection itself
	if eventPath == subPath {
		return true
	}

	// Check if eventPath is a direct child of subPath
	if strings.HasPrefix(eventPath, subPath) {
		remainder := strings.TrimPrefix(eventPath, subPath)
		// Should be just the doc name (no more slashes for direct children)
		if !strings.Contains(remainder, "/") && remainder != "" {
			// Check interval filter
			if sub.Interval != nil {
				return sub.Interval.Matches(remainder)
			}
			return true
		}
	}

	return false
}

func jsonString(s string) string {
	b, _ := json.Marshal(s)
	return string(b)
}

package db

import (
	"crypto/rand"
	"encoding/base64"
)

// generateID generates a random unique string for POST document names and tokens.
func generateID() string {
	b := make([]byte, 12)
	_, _ = rand.Read(b)
	return base64.RawURLEncoding.EncodeToString(b)
}

package handlers

import (
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-bench/auth"
	"github.com/RICE-COMP318-FALL24/owldb-bench/db"
)

// Handler manages HTTP requests.
type Handler struct {
	db   *db.DatabaseServer
	auth *auth.AuthManager
}

// NewHandler creates a new Handler.
func NewHandler(database *db.DatabaseServer, authMgr *auth.AuthManager) *Handler {
	return &Handler{
		db:   database,
		auth: authMgr,
	}
}

// ServeHTTP routes requests.
func (h *Handler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	path := r.URL.Path

	// Handle OPTIONS without auth
	if r.Method == http.MethodOptions {
		h.handleOptions(w, r)
		return
	}

	// Handle auth endpoint
	if path == "/auth" || path == "/auth/" {
		h.handleAuth(w, r)
		return
	}

	// All other endpoints require auth (except OPTIONS already handled)
	username, err := h.authenticate(r)
	if err != nil {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	// Must start with /v1/
	if !strings.HasPrefix(path, "/v1/") {
		writeError(w, http.StatusBadRequest, "Invalid path")
		return
	}

	// Extract the resource path after /v1/
	resourcePath := strings.TrimPrefix(path, "/v1/")

	// Determine if this is a collection path (ends with /) or document path
	isCollection := strings.HasSuffix(resourcePath, "/")

	if isCollection {
		// Remove trailing slash for internal processing
		trimmedPath := strings.TrimSuffix(resourcePath, "/")
		h.handleCollectionRequest(w, r, trimmedPath, username)
	} else {
		h.handleDocumentRequest(w, r, resourcePath, username)
	}
}

func (h *Handler) authenticate(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return "", fmt.Errorf("no authorization header")
	}

	if !strings.HasPrefix(authHeader, "Bearer ") {
		return "", fmt.Errorf("invalid authorization header")
	}

	token := strings.TrimPrefix(authHeader, "Bearer ")
	return h.auth.Validate(token)
}

func (h *Handler) handleAuth(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodPost:
		h.handleLogin(w, r)
	case http.MethodDelete:
		h.handleLogout(w, r)
	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (h *Handler) handleLogin(w http.ResponseWriter, r *http.Request) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	defer r.Body.Close()

	var loginReq struct {
		Username string `json:"username"`
	}
	if err := json.Unmarshal(body, &loginReq); err != nil {
		writeError(w, http.StatusBadRequest, "Invalid JSON in request body")
		return
	}

	if loginReq.Username == "" {
		writeError(w, http.StatusBadRequest, "No username in request body")
		return
	}

	token, err := h.auth.Login(loginReq.Username)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "Failed to create token")
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"token": token})
}

func (h *Handler) handleLogout(w http.ResponseWriter, r *http.Request) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" || !strings.HasPrefix(authHeader, "Bearer ") {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	token := strings.TrimPrefix(authHeader, "Bearer ")
	if err := h.auth.Logout(token); err != nil {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	w.WriteHeader(http.StatusNoContent)
}

func (h *Handler) handleCollectionRequest(w http.ResponseWriter, r *http.Request, path string, username string) {
	// path has trailing slash removed
	// If path has no "/" it's a database name

	parts := strings.Split(path, "/")
	isDatabase := len(parts) == 1

	switch r.Method {
	case http.MethodGet:
		h.handleGetCollection(w, r, path)
	case http.MethodPut:
		if isDatabase {
			h.handleCreateDatabase(w, r, path)
		} else {
			h.handleCreateCollection(w, r, path)
		}
	case http.MethodDelete:
		if isDatabase {
			h.handleDeleteDatabase(w, r, path)
		} else {
			h.handleDeleteCollection(w, r, path)
		}
	case http.MethodPost:
		h.handlePostDocument(w, r, path, username)
	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (h *Handler) handleDocumentRequest(w http.ResponseWriter, r *http.Request, path string, username string) {
	switch r.Method {
	case http.MethodGet:
		h.handleGetDocument(w, r, path)
	case http.MethodPut:
		h.handlePutDocument(w, r, path, username)
	case http.MethodDelete:
		h.handleDeleteDocument(w, r, path)
	case http.MethodPatch:
		h.handlePatchDocument(w, r, path, username)
	default:
		writeError(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

func (h *Handler) handleCreateDatabase(w http.ResponseWriter, r *http.Request, name string) {
	if err := h.db.CreateDatabase(name); err != nil {
		if strings.Contains(err.Error(), "already exists") {
			writeError(w, http.StatusConflict, "Database already exists")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	uri := "/v1/" + name + "/"
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", uri)
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{"uri": uri})
}

func (h *Handler) handleDeleteDatabase(w http.ResponseWriter, r *http.Request, name string) {
	if err := h.db.DeleteDatabase(name); err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, "Database does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}
	w.WriteHeader(http.StatusNoContent)
}

func (h *Handler) handleGetCollection(w http.ResponseWriter, r *http.Request, path string) {
	// Check for subscribe mode
	mode := r.URL.Query().Get("mode")
	if mode == "subscribe" {
		h.handleSubscribeCollection(w, r, path)
		return
	}

	// Parse interval
	intervalStr := r.URL.Query().Get("interval")
	start, end, hasStart, hasEnd, err := parseInterval(intervalStr)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Invalid interval: "+err.Error())
		return
	}

	docs, err := h.db.GetCollectionDocs(path, start, end, hasStart, hasEnd)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			if strings.Contains(err.Error(), "database") {
				writeError(w, http.StatusNotFound, "Database does not exist")
			} else {
				writeError(w, http.StatusNotFound, "Collection does not exist")
			}
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	if docs == nil {
		docs = []db.DocResponse{}
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(docs)
}

func (h *Handler) handleGetDocument(w http.ResponseWriter, r *http.Request, path string) {
	// Check for subscribe mode
	mode := r.URL.Query().Get("mode")
	if mode == "subscribe" {
		h.handleSubscribeDocument(w, r, path)
		return
	}

	data, meta, fullPath, err := h.db.GetDocument(path)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			if strings.Contains(err.Error(), "database") {
				writeError(w, http.StatusNotFound, "Database does not exist")
			} else if strings.Contains(err.Error(), "collection") {
				writeError(w, http.StatusNotFound, "Collection does not exist")
			} else {
				writeError(w, http.StatusNotFound, "Document does not exist")
			}
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	resp := db.DocResponse{
		Path: fullPath,
		Doc:  json.RawMessage(data),
		Meta: meta,
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(resp)
}

func (h *Handler) handlePutDocument(w http.ResponseWriter, r *http.Request, path string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	defer r.Body.Close()

	if len(body) == 0 {
		writeError(w, http.StatusBadRequest, "Empty request body")
		return
	}

	mode := r.URL.Query().Get("mode")
	noOverwrite := mode == "nooverwrite"

	created, uri, err := h.db.PutDocument(path, body, username, noOverwrite)
	if err != nil {
		errMsg := err.Error()
		if strings.Contains(errMsg, "already exists") {
			writeError(w, http.StatusPreconditionFailed, "Document already exists")
			return
		}
		if strings.Contains(errMsg, "does not exist") {
			if strings.Contains(errMsg, "database") {
				writeError(w, http.StatusNotFound, "Database does not exist")
			} else if strings.Contains(errMsg, "collection") {
				writeError(w, http.StatusNotFound, "Collection does not exist")
			} else {
				writeError(w, http.StatusNotFound, "Resource does not exist")
			}
			return
		}
		if strings.Contains(errMsg, "schema") || strings.Contains(errMsg, "invalid JSON") {
			writeError(w, http.StatusBadRequest, errMsg)
			return
		}
		writeError(w, http.StatusBadRequest, errMsg)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", uri)
	if created {
		w.WriteHeader(http.StatusCreated)
	} else {
		w.WriteHeader(http.StatusOK)
	}
	json.NewEncoder(w).Encode(map[string]string{"uri": uri})
}

func (h *Handler) handleDeleteDocument(w http.ResponseWriter, r *http.Request, path string) {
	if err := h.db.DeleteDocument(path); err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}
	w.WriteHeader(http.StatusNoContent)
}

func (h *Handler) handlePatchDocument(w http.ResponseWriter, r *http.Request, path string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	defer r.Body.Close()

	var patches []db.PatchOp
	if err := json.Unmarshal(body, &patches); err != nil {
		writeError(w, http.StatusBadRequest, "Invalid JSON in request body")
		return
	}

	uri, patchFailed, message, err := h.db.PatchDocument(path, patches, username)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", uri)
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]interface{}{
		"uri":         uri,
		"patchFailed": patchFailed,
		"message":     message,
	})
}

func (h *Handler) handlePostDocument(w http.ResponseWriter, r *http.Request, collPath string, username string) {
	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Failed to read request body")
		return
	}
	defer r.Body.Close()

	if len(body) == 0 {
		writeError(w, http.StatusBadRequest, "Empty request body")
		return
	}

	// collPath is like "dbname" or "dbname/doc/col"
	uri, err := h.db.PostDocument(collPath, body, username)
	if err != nil {
		errMsg := err.Error()
		if strings.Contains(errMsg, "does not exist") {
			if strings.Contains(errMsg, "database") {
				writeError(w, http.StatusNotFound, "Database does not exist")
			} else {
				writeError(w, http.StatusNotFound, "Collection does not exist")
			}
			return
		}
		if strings.Contains(errMsg, "schema") || strings.Contains(errMsg, "invalid JSON") {
			writeError(w, http.StatusBadRequest, errMsg)
			return
		}
		writeError(w, http.StatusBadRequest, errMsg)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", uri)
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{"uri": uri})
}

func (h *Handler) handleCreateCollection(w http.ResponseWriter, r *http.Request, path string) {
	uri, err := h.db.CreateCollection(path)
	if err != nil {
		errMsg := err.Error()
		if strings.Contains(errMsg, "already exists") {
			writeError(w, http.StatusConflict, "Collection already exists")
			return
		}
		if strings.Contains(errMsg, "does not exist") {
			if strings.Contains(errMsg, "database") {
				writeError(w, http.StatusNotFound, "Database does not exist")
			} else {
				writeError(w, http.StatusNotFound, "Document does not exist")
			}
			return
		}
		writeError(w, http.StatusBadRequest, errMsg)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", uri)
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{"uri": uri})
}

func (h *Handler) handleDeleteCollection(w http.ResponseWriter, r *http.Request, path string) {
	if err := h.db.DeleteCollection(path); err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, "Collection does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}
	w.WriteHeader(http.StatusNoContent)
}

func (h *Handler) handleOptions(w http.ResponseWriter, r *http.Request) {
	path := r.URL.Path

	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
	w.Header().Set("Access-Control-Max-Age", "86400")

	// Determine allowed methods based on path type
	var allow string
	if strings.HasSuffix(path, "/") {
		// Collection or database path
		allow = "GET, PUT, POST, DELETE, OPTIONS"
	} else {
		// Document path
		allow = "GET, PUT, DELETE, PATCH, OPTIONS"
	}

	w.Header().Set("Allow", allow)
	w.Header().Set("Access-Control-Allow-Methods", allow)
	w.WriteHeader(http.StatusOK)
}

// SSE Subscription handlers

func (h *Handler) handleSubscribeDocument(w http.ResponseWriter, r *http.Request, path string) {
	// Verify document exists first
	data, meta, fullPath, err := h.db.GetDocument(path)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	flusher, ok := w.(http.Flusher)
	if !ok {
		writeError(w, http.StatusInternalServerError, "Streaming not supported")
		return
	}

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)
	flusher.Flush()

	// Subscribe
	sub := h.db.Subs().Subscribe(fullPath, nil)
	defer h.db.Subs().Unsubscribe(sub.ID)

	// Send initial state
	metaJSON, _ := json.Marshal(meta)
	eventData := fmt.Sprintf(`{"path":%s,"doc":%s,"meta":%s}`,
		jsonStr(fullPath), string(data), string(metaJSON))

	writeSSEEvent(w, "update", eventData)
	flusher.Flush()

	// Keep-alive ticker
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	ctx := r.Context()
	for {
		select {
		case <-ctx.Done():
			return
		case <-sub.Done:
			return
		case event, ok := <-sub.Events:
			if !ok {
				return
			}
			writeSSEEvent(w, event.EventType, event.Data)
			flusher.Flush()
		case <-ticker.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		}
	}
}

func (h *Handler) handleSubscribeCollection(w http.ResponseWriter, r *http.Request, path string) {
	// Parse interval
	intervalStr := r.URL.Query().Get("interval")
	start, end, hasStart, hasEnd, err := parseInterval(intervalStr)
	if err != nil {
		writeError(w, http.StatusBadRequest, "Invalid interval: "+err.Error())
		return
	}

	// Verify collection exists and get initial docs
	docs, err := h.db.GetCollectionDocs(path, start, end, hasStart, hasEnd)
	if err != nil {
		if strings.Contains(err.Error(), "does not exist") {
			writeError(w, http.StatusNotFound, "Collection does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	flusher, ok := w.(http.Flusher)
	if !ok {
		writeError(w, http.StatusInternalServerError, "Streaming not supported")
		return
	}

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)
	flusher.Flush()

	// Set up interval filter
	var filter *db.IntervalFilter
	if hasStart || hasEnd {
		filter = &db.IntervalFilter{
			HasLow: hasStart, Low: start,
			HasHigh: hasEnd, High: end,
		}
	}

	// Figure out collection full path
	colFullPath := "/v1/" + path + "/"

	sub := h.db.Subs().Subscribe(colFullPath, filter)
	defer h.db.Subs().Unsubscribe(sub.ID)

	// Send initial state for each document
	for _, doc := range docs {
		metaJSON, _ := json.Marshal(doc.Meta)
		eventData := fmt.Sprintf(`{"path":%s,"doc":%s,"meta":%s}`,
			jsonStr(doc.Path), string(doc.Doc), string(metaJSON))
		writeSSEEvent(w, "update", eventData)
	}
	flusher.Flush()

	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	ctx := r.Context()
	for {
		select {
		case <-ctx.Done():
			return
		case <-sub.Done:
			return
		case event, ok := <-sub.Events:
			if !ok {
				return
			}
			writeSSEEvent(w, event.EventType, event.Data)
			flusher.Flush()
		case <-ticker.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		}
	}
}

func writeSSEEvent(w http.ResponseWriter, eventType, data string) {
	id := fmt.Sprintf("%d", time.Now().UnixMilli())
	fmt.Fprintf(w, "event: %s\n", eventType)
	// Split data on newlines
	for _, line := range strings.Split(data, "\n") {
		fmt.Fprintf(w, "data: %s\n", line)
	}
	fmt.Fprintf(w, "id: %s\n\n", id)
}

func writeError(w http.ResponseWriter, status int, message string) {
	slog.Debug("Error response", "status", status, "message", message)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(map[string]string{"error": message})
}

func jsonStr(s string) string {
	b, _ := json.Marshal(s)
	return string(b)
}

// parseInterval parses an interval string like "[low,high]".
func parseInterval(s string) (start, end string, hasStart, hasEnd bool, err error) {
	if s == "" {
		return "", "", false, false, nil
	}

	if !strings.HasPrefix(s, "[") || !strings.HasSuffix(s, "]") {
		return "", "", false, false, fmt.Errorf("interval must be in format [low,high]")
	}

	inner := s[1 : len(s)-1]
	commaIdx := strings.Index(inner, ",")
	if commaIdx == -1 {
		return "", "", false, false, fmt.Errorf("interval must contain a comma")
	}

	low := inner[:commaIdx]
	high := inner[commaIdx+1:]

	if low != "" {
		hasStart = true
		start = low
	}
	if high != "" {
		hasEnd = true
		end = high
	}

	return start, end, hasStart, hasEnd, nil
}

// OwlDB - a RESTful NoSQL document database.
package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"

	"github.com/RICE-COMP318-FALL24/owldb-bench/auth"
	"github.com/RICE-COMP318-FALL24/owldb-bench/db"
	"github.com/RICE-COMP318-FALL24/owldb-bench/handlers"
	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

func main() {
	var server http.Server
	var port int
	var err error

	// Parse command line flags
	portFlag := flag.Int("p", 3318, "Port to listen on")
	schemaFile := flag.String("s", "", "JSON schema file for document validation")
	tokenFile := flag.String("t", "", "JSON file mapping usernames to tokens")
	flag.Parse()

	port = *portFlag

	// Schema is required
	if *schemaFile == "" {
		slog.Error("Schema file is required (-s flag)")
		os.Exit(1)
	}

	// Load and compile schema
	schema, err := jsonschema.Compile(*schemaFile)
	if err != nil {
		slog.Error("Failed to compile schema", "error", err)
		os.Exit(1)
	}

	// Create database server
	database := db.NewDatabaseServer(schema)

	// Create auth manager
	authMgr := auth.NewAuthManager()

	// Load pre-configured tokens
	if *tokenFile != "" {
		tokenData, err := os.ReadFile(*tokenFile)
		if err != nil {
			slog.Error("Failed to read token file", "error", err)
			os.Exit(1)
		}
		var tokenMap map[string]string
		if err := json.Unmarshal(tokenData, &tokenMap); err != nil {
			slog.Error("Failed to parse token file", "error", err)
			os.Exit(1)
		}
		authMgr.LoadTokens(tokenMap)
	}

	// Create handler
	handler := handlers.NewHandler(database, authMgr)

	// Configure server
	mux := http.NewServeMux()
	mux.Handle("/", handler)
	server.Handler = mux
	server.Addr = fmt.Sprintf(":%d", port)

	// The following code should go last and remain unchanged.
	// Note that you must actually initialize 'server' and 'port'
	// before this.  Note that the server is started below by
	// calling ListenAndServe.  You must not start the server
	// before this.

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err = server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

package skiplist

import (
	"cmp"
	"context"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 16

// UpdateCheck is a function used by Upsert to conditionally update or insert.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair holds a key-value pair.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// node represents a skip list node with lazy deletion support.
type node[K cmp.Ordered, V any] struct {
	key        K
	value      V
	next       []*node[K, V]
	marked     atomic.Bool
	fullyLinked atomic.Bool
	mu         sync.Mutex
	topLevel   int
}

func newNode[K cmp.Ordered, V any](key K, value V, level int) *node[K, V] {
	n := &node[K, V]{
		key:      key,
		value:    value,
		next:     make([]*node[K, V], level+1),
		topLevel: level,
	}
	return n
}

// SkipList is a concurrent skip list with lazy synchronization.
type SkipList[K cmp.Ordered, V any] struct {
	head *node[K, V]
}

// New creates a new empty skip list.
func New[K cmp.Ordered, V any]() *SkipList[K, V] {
	head := &node[K, V]{
		next:     make([]*node[K, V], maxLevel),
		topLevel: maxLevel - 1,
	}
	head.fullyLinked.Store(true)
	return &SkipList[K, V]{
		head: head,
	}
}

func randomLevel() int {
	level := 0
	for level < maxLevel-1 && rand.Float64() < 0.5 {
		level++
	}
	return level
}

// findNode finds the predecessors and successors for a key at each level.
// Returns the level at which the key was found, or -1 if not found.
func (sl *SkipList[K, V]) findNode(key K, preds, succs []*node[K, V]) int {
	found := -1
	pred := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.next[level]
		for curr != nil && curr.key < key {
			pred = curr
			curr = pred.next[level]
		}
		if found == -1 && curr != nil && curr.key == key {
			found = level
		}
		preds[level] = pred
		succs[level] = curr
	}
	return found
}

// lockUniquePreds locks each unique predecessor node exactly once,
// in order from level 0 to topLevel. Returns the set of locked nodes
// for unlocking, and whether validation passed.
func lockUniquePreds[K cmp.Ordered, V any](preds, succs []*node[K, V], topLevel int) ([]*node[K, V], bool) {
	locked := make([]*node[K, V], 0, topLevel+1)
	valid := true

	for level := 0; level <= topLevel && valid; level++ {
		pred := preds[level]
		succ := succs[level]

		// Only lock if we haven't locked this node already
		alreadyLocked := false
		for _, n := range locked {
			if n == pred {
				alreadyLocked = true
				break
			}
		}

		if !alreadyLocked {
			pred.mu.Lock()
			locked = append(locked, pred)
		}

		// Validate
		valid = !pred.marked.Load() &&
			(succ == nil || !succ.marked.Load()) &&
			pred.next[level] == succ
	}

	return locked, valid
}

func unlockAll[K cmp.Ordered, V any](nodes []*node[K, V]) {
	for _, n := range nodes {
		n.mu.Unlock()
	}
}

// Upsert either updates or inserts a key using the provided check function.
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (bool, error) {
	topLevel := randomLevel()

	for {
		preds := make([]*node[K, V], maxLevel)
		succs := make([]*node[K, V], maxLevel)
		found := sl.findNode(key, preds, succs)

		if found != -1 {
			nodeFound := succs[found]
			if !nodeFound.marked.Load() {
				// Wait until fully linked
				for !nodeFound.fullyLinked.Load() {
				}
				// Lock for update
				nodeFound.mu.Lock()
				if nodeFound.marked.Load() {
					nodeFound.mu.Unlock()
					continue
				}
				newValue, err := check(key, nodeFound.value, true)
				if err != nil {
					nodeFound.mu.Unlock()
					return false, err
				}
				nodeFound.value = newValue
				nodeFound.mu.Unlock()
				return true, nil
			}
			continue
		}

		// Insert
		locked, valid := lockUniquePreds(preds, succs, topLevel)

		if !valid {
			unlockAll(locked)
			continue
		}

		var zeroV V
		newValue, err := check(key, zeroV, false)
		if err != nil {
			unlockAll(locked)
			return false, err
		}

		nn := newNode(key, newValue, topLevel)
		for level := 0; level <= topLevel; level++ {
			nn.next[level] = succs[level]
			preds[level].next[level] = nn
		}
		nn.fullyLinked.Store(true)

		unlockAll(locked)
		return false, nil
	}
}

// Find looks up a key and returns its value.
func (sl *SkipList[K, V]) Find(key K) (V, bool) {
	preds := make([]*node[K, V], maxLevel)
	succs := make([]*node[K, V], maxLevel)
	found := sl.findNode(key, preds, succs)
	if found == -1 {
		var zero V
		return zero, false
	}
	n := succs[found]
	if n.fullyLinked.Load() && !n.marked.Load() {
		return n.value, true
	}
	var zero V
	return zero, false
}

// Remove removes a key from the skip list.
func (sl *SkipList[K, V]) Remove(key K) (V, bool) {
	var victim *node[K, V]
	isMarked := false
	topLevel := -1

	for {
		preds := make([]*node[K, V], maxLevel)
		succs := make([]*node[K, V], maxLevel)
		found := sl.findNode(key, preds, succs)

		if found != -1 {
			victim = succs[found]
		}

		if isMarked ||
			(found != -1 &&
				victim.fullyLinked.Load() &&
				victim.topLevel == found &&
				!victim.marked.Load()) {

			if !isMarked {
				topLevel = victim.topLevel
				victim.mu.Lock()
				if victim.marked.Load() {
					victim.mu.Unlock()
					var zero V
					return zero, false
				}
				victim.marked.Store(true)
				isMarked = true
			}

			// Lock unique predecessors
			locked := make([]*node[K, V], 0, topLevel+1)
			valid := true
			for level := 0; level <= topLevel && valid; level++ {
				pred := preds[level]
				alreadyLocked := false
				for _, n := range locked {
					if n == pred {
						alreadyLocked = true
						break
					}
				}
				if !alreadyLocked {
					pred.mu.Lock()
					locked = append(locked, pred)
				}
				valid = !pred.marked.Load() && pred.next[level] == victim
			}

			if !valid {
				unlockAll(locked)
				continue
			}

			for level := topLevel; level >= 0; level-- {
				preds[level].next[level] = victim.next[level]
			}
			victim.mu.Unlock()
			unlockAll(locked)
			return victim.value, true
		}

		var zero V
		return zero, false
	}
}

// Query returns all key-value pairs in [start, end] order.
func (sl *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	curr := sl.head
	for level := maxLevel - 1; level >= 0; level-- {
		for curr.next[level] != nil && curr.next[level].key < start {
			curr = curr.next[level]
		}
	}

	curr = curr.next[0]
	for curr != nil && curr.key <= end {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if curr.fullyLinked.Load() && !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}
	return results, nil
}

// QueryAll returns all key-value pairs in order.
func (sl *SkipList[K, V]) QueryAll(ctx context.Context) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	curr := sl.head.next[0]
	for curr != nil {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if curr.fullyLinked.Load() && !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}
	return results, nil
}

